import scala.xml.{XML, Node}

class ConfigService {

  def parseConfig(xmlString: String): Map[String, String] = {
    val xml = XML.loadString(xmlString)
    extractSettings(xml)
  }

  private def extractSettings(node: Node): Map[String, String] = {
    node.child.collect {
      case elem: scala.xml.Elem =>
        elem.label -> elem.text
    }.toMap ++ node.child.flatMap {
      case child: scala.xml.Elem => extractSettings(child)
      case _ => Map.empty
    }
  }
}

object ConfigService {
  def main(args: Array[String]): Unit = {
    val configService = new ConfigService()
    val xmlString =
      """<config>
        |  <setting name="database">localhost</setting>
        |  <setting name="port">8080</setting>
        |  <subConfig>
        |    <setting name="timeout">30</setting>
        |  </subConfig>
        |</config>""".stripMargin

    val settings = configService.parseConfig(xmlString)
    println(settings)
  }
}